async (page) => {
  // Keep chopping oaks - click E0 (current target oak) repeatedly
  for (let i = 0; i < 5; i++) {
    const legend = await page.evaluate(() => {
      const m = window.__latestAsciiMap;
      return m && !m.error ? m.legendText.substring(0, 600) : 'error';
    });
    // Find first oak in legend
    const oakMatch = legend.match(/E(\d+) \[\^?\T?\] Oak/);
    const label = oakMatch ? 'E' + oakMatch[1] : 'E0';
    await page.evaluate((label) => window.__clickEntity(label), label);
    await page.waitForTimeout(4000);

    const inv = await page.evaluate(() => {
      const s = window.__latestGameState;
      const logs = s.inventory.find(i => i.name === 'Logs' || i.key === 'log');
      return {logs: logs ? logs.count : 0, all: s.inventory.map(i=>i.name+':'+i.count)};
    });
    console.log('After chop', i+1, ':', JSON.stringify(inv));
    if (inv.logs >= 10) break;
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({
      pos: s.player_position,
      inventory: s.inventory.map(i => ({name: i.name, count: i.count})),
      quest: s.quests.find(q => q.key === 'foresting')
    });
  });
  return finalState;
}

async (page) => {
  // Click RESPAWN button
  await page.evaluate(() => {
    const buttons = document.querySelectorAll('button, .btn, [class*="respawn"]');
    for (const btn of buttons) {
      if (btn.textContent.toUpperCase().includes('RESPAWN')) {
        btn.click();
        return;
      }
    }
    // Try clicking by canvas coordinates - button appears to be center screen
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', {clientX: 640, clientY: 364, bubbles: true, ctrlKey: false}));
  });
  await page.waitForTimeout(3000);

  // Warp to Mudwich immediately
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(3000);

  // Set attack style to Hack
  await page.evaluate(() => window.game.player.setAttackStyle(0));

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({pos: s.player_position, hp: s.player_stats.hp, max_hp: s.player_stats.max_hp, inventory: s.inventory.map(i=>i.name+':'+i.count)});
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return state;
}

